{
  "mode": "method",
  "tests": [
    {
      "name": "valid_project_creation",
      "input": {
        "name": "New Project",
        "description": "A project to modernize the service.",
        "status": "active"
      },
      "output": {
        "id": "1",
        "name": "New Project",
        "description": "A project to modernize the service.",
        "status": "active"
      },
      "notes": "Validates successful creation of a project."
    },
    {
      "name": "project_member_association",
      "input": {
        "projectId": "1",
        "userId": "user123",
        "role": "admin",
        "isPrimary": true
      },
      "output": {
        "projectId": "1",
        "userId": "user123",
        "role": "admin",
        "isPrimary": true
      },
      "notes": "Validates successful association of a user with a project."
    },
    {
      "name": "project_attachment_upload",
      "input": {
        "projectId": "1",
        "fileName": "document.pdf",
        "fileType": "application/pdf"
      },
      "output": {
        "projectId": "1",
        "fileName": "document.pdf",
        "fileType": "application/pdf",
        "attachmentId": "attach1"
      },
      "notes": "Validates successful upload of an attachment to a project."
    },
    {
      "name": "invalid_project_creation_missing_fields",
      "input": {
        "name": "",
        "description": "Missing name.",
        "status": "active"
      },
      "output": {
        "error": "Project name is required."
      },
      "notes": "Tests edge case of missing required fields."
    },
    {
      "name": "duplicate_project_creation",
      "input": {
        "name": "New Project",
        "description": "A project to modernize the service.",
        "status": "active"
      },
      "output": {
        "error": "Project with this name already exists."
      },
      "notes": "Tests edge case of creating a project with a duplicate name."
    },
    {
      "name": "project_member_invalid_role",
      "input": {
        "projectId": "1",
        "userId": "user123",
        "role": "invalid_role",
        "isPrimary": true
      },
      "output": {
        "error": "Invalid role specified."
      },
      "notes": "Tests edge case of providing an invalid role for a project member."
    },
    {
      "name": "attachment_upload_invalid_file_type",
      "input": {
        "projectId": "1",
        "fileName": "script.exe",
        "fileType": "application/x-msdownload"
      },
      "output": {
        "error": "Invalid file type."
      },
      "notes": "Tests edge case of uploading an attachment with an unsupported file type."
    },
    {
      "name": "project_retrieval_by_id",
      "input": {
        "projectId": "1"
      },
      "output": {
        "id": "1",
        "name": "New Project",
        "description": "A project to modernize the service.",
        "status": "active"
      },
      "notes": "Validates retrieval of a project by its ID."
    }
  ],
  "assumptions": "All inputs are sanitized and validated before processing.",
  "notes": "Ensure that the schema supports all required queries efficiently."
}
